module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

reg [size-1:0] mul_a_reg;
reg [size-1:0] mul_b_reg;
reg [size*2-1:0] partial_products [size-1:0];
reg [size*2-1:0] sum_reg [1:0];

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
        for (int i = 0; i < size; i++) begin
            partial_products[i] <= 0;
        end
        for (int i = 0; i < 2; i++) begin
            sum_reg[i] <= 0;
        end
        mul_out <= 0;
    end else begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
        for (int i = 0; i < size; i++) begin
            partial_products[i] <= (mul_b_reg[i]) ? {mul_a_reg, 4'b0} << i : 'd0;
        end
        sum_reg[0] <= partial_products[0] + partial_products[1];
        sum_reg[1] <= partial_products[2] + partial_products[3];
        mul_out <= sum_reg[0] + sum_reg[1];
    end
end

endmodule
